  'Validation is a one-time event — once validated, you never need to test assumptions again.': { prompt: "La validation est un événement unique — une fois validé, vous n'avez plus jamais besoin de tester vos hypothèses.", options: ["Vrai", "Faux"], correctAnswer: "Faux" },
